      // Semen
      { en: 'Semen Analysis', ar: 'تحليل السائل المنوي', cat: 'Special', range: 'See WHO Criteria', cost: 35 },
    ];
    const lStmt = db.prepare('INSERT INTO lab_tests (name_en, name_ar, category_en, cost, normal_range) VALUES (?, ?, ?, ?, ?)');
