      { en: 'Wound Dressing (Major)', ar: 'غيار جروح كبير', cost: 45 },
      { en: 'Vital Signs Monitoring', ar: 'مراقبة العلامات الحيوية', cost: 15 },
      { en: 'ECG Recording', ar: 'رسم قلب', cost: 50 },
      { en: 'Nebulizer Therapy', ar: 'جلسة بخار', cost: 20 },
